    print()

def fibonacci(n):
    a, b = 0, 1
    result = []
    for _ in range(n):
        result.append(a)
        a, b = b, a + b
    return result

print(fibonacci(10))

# Check if Fibonacci
import math
def is_fib(n):
    def perfect_square(x):
        s = int(math.sqrt(x))
        return s*s == x
    return perfect_square(5*n*n + 4) or perfect_square(5*n*n - 4)

for i in range(15):
    if is_fib(i):
        print(i, end=' ')

def sieve(n):
    primes = [True] * (n+1)
    primes[0] = primes[1] = False
    for i in range(2, int(n**0.5)+1):
        if primes[i]:
            for j in range(i*i, n+1, i):
                primes[j] = False
    return [i for i in range(n+1) if primes[i]]

print(sieve(50))
